















import Vue from 'vue';
import {createComponent, reactive, ref, onMounted, SetupContext} from "@vue/composition-api";
import {board_manager_factory} from '../storage';
import {AbstractBoardManager, Board} from '../storage/header';
import {generate_uuid} from '../storage/uuid';
import ModalClose from './chips/modal-close-button.vue';

type Props = {};


export default createComponent({
    components: {
        'modal-close': ModalClose
    },
    setup(props: Props, { parent }: SetupContext) {
        let store = parent.$store;
        let router = parent.$parent.$router;//parent.$router;
        let board_manager: AbstractBoardManager = null;
        let boards = reactive([]);


        onMounted(async () => {
            board_manager = await board_manager_factory();
            boards.length = 0;
            let bs = await board_manager.get_boards();
            boards.push(...bs);
        })

        const close_model = () => {
            store.commit('modal_close');
        }

        const change_db = (board: Board) => {
            router.push({name: 'board', params: {board_path: board.path}});
            store.commit('modal_close');
        }

        /**
         * ボードの新規作成
         */
        const new_board = (e) => {
            const path = generate_uuid();
            // ボード新規作成
            router.push({name: 'board', params:{board_path: path}});
            store.commit('modal_close');
        }

        return {boards, close_model, change_db, new_board}
    }
});

