import Vue from 'vue';
import Component, { mixins } from 'vue-class-component';
import {Img, Position, AbstractStorage, ImgWithPosition, Board, AbstractBoardManager} from './storage/header';
import Compressor from './storage/compressor';
import {LocalStorage} from './storage/storage_on_local';

@Component
export default class BoardComponent extends Vue {

    /**board-mainクラス上でのマウス座標計算
     * 子オブジェクト上で発火した場合親まで再帰的に座標を加算していく
     * @returns 座標を返却（zoom_rateには左右されない）
     */
    get_offset(e) {
        const inner_get = (elem): number[] => {
            if(elem.classList.contains("board-main")){return [0, 0]}
            const [x, y] = inner_get(elem.offsetParent);
            return [elem.offsetTop + y, elem.offsetLeft + x];
        }
        const [x, y] = inner_get(e.target);

        return [x + e.offsetX, y + e.offsetY];
    }

}
