import Vue from 'vue';
import Component, { mixins } from 'vue-class-component';
import {Img, Position, AbstractStorage, ImgWithPosition, Board, AbstractBoardManager} from './storage/header';
import Compressor from './storage/compressor';
import {LocalStorage} from './storage/storage_on_local';

@Component
export default class BoardComponent extends Vue {

    // ts suppression
    imgs_index: Map<string, ImgWithPosition>
    storage: AbstractStorage
    view_img_ids: string[]
    zoom_rate: number

    /**
     * 容量を削減したblobにすり替える処理
     */
    async replace_reduce_blob() {
        const st = this.storage as LocalStorage;
        const rt = st.reduce_table;

        for(let id of this.view_img_ids) {
            const iwp = this.imgs_index.get(id);
            const deno =
                Compressor.prototype.calc_reduce_deno(iwp.img.width, iwp.pos.fixed_width, this.zoom_rate);
            const rs = st.reduce_table.filter(x=>x<=deno).reverse();
            const fetch_deno = rs[0]; // 想定されるdeno

            if(fetch_deno != iwp.reduce_deno) {
                // DBにアクセスすると遅い
                const c = await this.storage.get_compress(iwp.id, deno);
                if(c != null) {
                    this.$set(iwp.img, 'blob', c.blob);
                    this.$set(iwp, 'reduce_deno', c.reduce_deno);
                } else if(iwp.reduce_deno != 1) {
                    // 圧縮できるサイズがない場合
                    // 元画像を使用する
                    const raw = await this.storage.get(iwp.id);
                    this.$set(iwp.img, 'blob', raw.img.blob);
                    this.$set(iwp, 'reduce_deno', 1);
                }
            }
        }
    }

}
