import {AbstractStorage, AbstractBoardManager, Img, Position, Compress, ImgWithPosition, Board, Theme} from './header';
import Compressor from './compressor';
import Dexie from 'dexie';

class BoardDB extends Dexie {

    boards: Dexie.Table<Board, string>;

    constructor() {
        super("board_metadata");

        this.version(1).stores({
            boards: "++path",
        }).upgrade(async trans => {
            const names = await Dexie.getDatabaseNames()
            for(let name of names) {
                let b = new Board(name, name);
                trans.boards.add(b);
            }
        });

        // width themeの追加
        this.version(2).stores({
            boards: "++path",
        }).upgrade(async trans => {
            const ttable = trans.boards as Dexie.Table<Board, string>;
            return ttable.toCollection().modify(record => {
                record.width = 100000;
                record.height = 150000;
                record.theme = Theme.CORKBOARD
            });
        });
        this.boards.mapToClass(Board)
    }
}


export class LocalBoardManager implements AbstractBoardManager {
    db: BoardDB;

    constructor() {
        this.db = new BoardDB();
    }
    async get_boards(): Promise<Board[]> {
        return this.db.boards.toArray()
    }

    async count_boards(): Promise<number> {
        return this.db.boards.count();
    }

    async get_board(path): Promise<Board> {
        return this.db.boards.get(path)
    }

    async delete_board(path): Promise<void> {
        const storage = new LocalStorage(path);
        await storage.destroy();
        return this.db.boards.delete(path)
    }

    async insert_board(board: Board) {
        return this.db.boards.add(board)
    }

    async update_board(board: Board) {
        return this.db.boards.update(board.path, board);
    }
}


class CorboardDB extends Dexie {

    img_attr: Dexie.Table<Img, string>;
    img_pos: Dexie.Table<Position, string>;
    img_compress: Dexie.Table<Compress, [string, number]>;

    constructor(board_name) {
        super(board_name);

        this.version(1).stores({
            img_storage: "++id, x, y, width, height, file",
            user_hostory: "zoom_rate, x, y",
        });

        this.version(2).stores({
            img_storage: "++id, x, y, width, height, file, orig_width, orig_height",
            user_hostory: "zoom_rate, x, y",
        }).upgrade(trans => {
            return trans.img_storage.toCollection().modify(img => {
                img.orig_height = img.height;
                img.orig_width = img.width;
            });
        });

        this.version(3).stores({ // db構造の分割
            img_storage: "++id", //deprecated
            img_attr: "",
            img_pos: "",
        }).upgrade(trans => {
            trans.img_storage.toCollection().modify(img => {
                let iid = img.id;
                let i = new Img(img.orig_width, img.orig_height, img.file.name, img.file);
                let p = new Position(img.x, img.y, img.width, img.height);
                this.img_attr.add(i, iid);
                this.img_pos.add(p, iid);
            });
        });

        this.version(4).stores({
            img_storage: null,
            img_attr: "",
            img_pos: "",
            img_compress: "",
        })

        this.img_attr.mapToClass(Img);
        this.img_pos.mapToClass(Position);
        this.img_compress.mapToClass(Compress);
    }
}

export class LocalStorage implements AbstractStorage {

    db: CorboardDB;
    board_manager: LocalBoardManager;
    // この圧縮率以外では圧縮しない
    reduce_table = [2, 4, 8].sort();//[2, 3, 4, 5, 6, 7, 8, 9, 10].sort();
    max_reduce = Math.min(...this.reduce_table);
    compressor: Compressor = new Compressor();

    constructor(board: Board) {
        this.db = new CorboardDB(board.path);
    }

    async destroy() {
        await this.db.delete();
    }

    async get_ids() {
        let imgs = await this.db.img_attr.toCollection();
        return imgs.keys();
    }

    async delete(img_id) {
        await this.db.transaction(
            'rw', this.db.img_attr,
            this.db.img_pos,
            this.db.img_compress, async () => {
                await this.db.img_attr.delete(img_id);
                await this.db.img_pos.delete(img_id);
                await this.delete_compress(img_id);
        })
    }

    /**該当縮小率のイメージを作成する */
    async set_compress(img_id: string, reduce_deno) {
        const iwp = await this.get(img_id);
        await this._set_compress(iwp, reduce_deno);
    }

    /**
     * 該当縮小率のイメージを作成する
     * iwpの再取得を避ける為の物
    */
    async _set_compress(iwp: ImgWithPosition, reduce_deno: number) {

        // あんまり小さい画像は作らない
        if(iwp.img.width * 1 / reduce_deno < 100) {return}
        if(iwp.img.height * 1 / reduce_deno < 100) {return}

        const blob = await this.compressor.compress(iwp, reduce_deno);
        const c = new Compress(iwp.id, reduce_deno, blob);
        await this.db.img_compress.add(c, [iwp.id, reduce_deno]);
    }

    normalize_reduce_deno(reduce_deno: number) {
        let rs = this.reduce_table.filter(x=>x<=reduce_deno).reverse();
        return rs[0];
    }

    /**
     * 圧縮された画像の中で一段上の画質の物を探す
     */
    async get_compress(img_id: string, reduce_deno: number): Promise<Compress> {
        if(reduce_deno<this.max_reduce){return null;}
        let rs = this.reduce_table.filter(x=>x<=reduce_deno).reverse();
        for(let rate of rs) {
            const img = await this.db.img_compress.get([img_id, rate]);
            if(img!=null) {
                return img
            }
        }
        // 圧縮されたものが無かった場合投げっぱなしで圧縮処理をかける
        if(rs.length > 0) {
            for(let r of rs) {
                this.set_compress(img_id, r);
            }
        }
        return null;
    }

    async get(img_id, zoom_rate?: number) {
        const [img, pos]: [Img, Position] = await Promise.all([
            this.db.img_attr.get(img_id),
            this.db.img_pos.get(img_id),
        ]);
        const iwp = new ImgWithPosition(img_id, img, pos);

        if(zoom_rate!=null) {
            // TODO: 初回ロードでcompressを取得すると相当遅くなる
            const reduce_deno = this.compressor.calc_reduce_deno(
                iwp.img.width, iwp.pos.fixed_width, zoom_rate);
            const comp = await this.get_compress(img_id, reduce_deno);
            if(comp!=null) {
                iwp.img.blob = comp.blob;
                iwp.reduce_deno = comp.reduce_deno;
            }
        }
        return iwp;
    }

    async update(img_id, img: Position) {
        await this.db.img_pos.update(img_id, img)
    }

    async set_compress_all(iwp: ImgWithPosition): Promise<void> {
        /**あるイメージの全ての圧縮比率で生成を行う */
        const l = this.reduce_table.map(r => this.db.img_compress.get([iwp.id, r]))
        const waits = (await Promise.all(l)).filter(x => x!=null);

        // 圧縮済みの物が存在しない物だけにする
        const not_exists = []
        for(let deno of this.reduce_table) {
            const c = waits.map(x => x.reduce_deno).includes(deno);
            if(!c) {
                not_exists.push(deno);
            }
        }
        await Promise.all(not_exists.map(r => this._set_compress(iwp, r)));
    }

    /**イメージに紐づく全ての圧縮キャッシュを削除 */
    async delete_compress(img_id: string) {
        const ps = []
        for(let rate of this.reduce_table) {
            // 存在しないkeyに対してdeleteを実行しても例外は発生しない
            ps.push(this.db.img_compress.delete([img_id, rate]));
        }
        await Promise.all(ps);
    }

    async insert(iwp: ImgWithPosition) {
        if(iwp.reduce_deno != 1) {
            console.warn('Upload compressed image.')
        }
        await Promise.all([
            this.db.img_attr.add(iwp.img, iwp.id),
            this.db.img_pos.add(iwp.pos, iwp.id)
        ]);
        // 圧縮処理を非同期で走らせる
        this.set_compress_all(iwp);
        return iwp.id
    }
}

class CompressKey {
    img_id: string
    reduce_deno: number
    constructor(img_id, reduce_deno) {
        this.img_id = img_id;
        this.reduce_deno = reduce_deno;
    }
}

/**
 * 圧縮イメージのキャッシュを使用する
 */
export class CachedLocalStorage extends LocalStorage {


    compress_cache = new Map();
    /**
     * 圧縮された画像の中で一段上の画質の物を探す
     */
    async get_compress(img_id: string, reduce_deno: number): Promise<Compress> {

        const rs = super.normalize_reduce_deno(reduce_deno);

        const key = JSON.stringify(new CompressKey(img_id, rs));
        const r = this.compress_cache.get(key);
        // nullとundefinedを使い分けている
        if(r!==undefined){return r}

        const img = await super.get_compress(img_id, reduce_deno);
        this.compress_cache.set(key, img);
        return img;
    }
}