export class ImgWithPosition {
    id: string;
    pos: Position;
    img: Img;
    reduce_deno: number = 1;

    constructor(id: string, img: Img, position: Position) {
        this.id = id;
        this.pos = position;
        this.img = img;
    }
}

export class Compress {
    id: string; // idとして使用する
    reduce_deno: number; // 縮小割合の分母　（1 / reduce_deno）
    blob: Blob;
    constructor(id: string, reduce_deno: number, blob: Blob) {
        Object.assign(this, {id, reduce_deno, blob})
    }
}

export class Position {
    x: number;
    y: number;
    fixed_width: number;
    fixed_height: number;

    constructor(x, y, fixed_width, fixed_height) {
        Object.assign(this, {x, y, fixed_width, fixed_height})
    }
}
export class Img {
    width: number;
    height: number;
    filename: string;
    blob: any;
    constructor(width, height, filename, blob) {
        Object.assign(this, {width, height, filename, blob})
    }
}

export enum Theme {
    CORKBOARD = 'corkboard',
    MONO_CHALKBLUE = 'mono_chalkblue',
}

export class Board {
    path: string; // idとして使用する
    name: string;
    width: number;
    height: number;
    theme: Theme;
    constructor(path, name, width, height, theme) {
        Object.assign(this, {path, name})
    }
}

export interface AbstractBoardManager {
    get_boards(): Promise<Board[]>
    get_board(path): Promise<Board>
    delete_board(path): Promise<void>
    count_boards(): Promise<number>
    update_board(db: Board)
    insert_board(db: Board)
}

export interface AbstractStorage {
    // DBを破棄
    destroy(): Promise<void>
    // imgのidの一覧を取得
    get_ids(): Promise<any[]>
    delete(id: string)
    // クライアント側ではredice_denoが計算できないのでzoom_rateを渡す
    get(id, zoom_rate?: number): Promise<ImgWithPosition>
    // 圧縮されたblobを取得
    get_compress(img_id: string, reduce_deno: number): Promise<Compress>
    update(id: string, pos: Position)
    insert(img: ImgWithPosition)
}