
































import Vue from 'vue';
import {Img, Position, AbstractStorage, ImgWithPosition, Board, AbstractBoardManager, Theme} from './storage/header';
import {storage_factory, board_manager_factory} from './storage';
import {CachedLocalStorage} from './storage/storage_on_local';
import {Watch, Component, Mixins} from 'vue-property-decorator';
import config_modal from './modal/config.vue';
import list_modal from './modal/list.vue';
import info_modal from './modal/info.vue';
import help_modal from './modal/help.vue';
import upload from './upload.vue';
import pinimg from './pinimg.vue';

// mixins
import img_resize  from './img_resize';
import img_upload  from './img_upload';
import img_compress  from './img_compress';
import img_zoom  from './img_zoom';
import img_move from './img_move';


Vue.directive('scroll', {
    inserted: function (el, binding) {
        let f = function (evt) {
            // 渡されたメソッドを呼び出す
            binding.value(evt, el);
        }
        el.addEventListener('scroll', f);
    }
});

Vue.directive('paste', {
    inserted: function (el, binding) {
        let f = function (evt) {
            // 渡されたメソッドを呼び出す
            binding.value(evt, el);
        }
        el.addEventListener('paste', f);
    }
});


@Component({
    components: {
        'pin-img': pinimg,
        'config': config_modal,
        'list': list_modal,
        'info': info_modal,
        'help': help_modal,
        'image-upload': upload,
    }
})
export default class BoardComponent extends Mixins(img_zoom, img_move, img_resize, img_upload, img_compress) {
    board: Board = new Board('', 'loading...', 0,0, 'corkboard');

    imgs: ImgWithPosition[] = [] // 全イメージ
    view_img_ids: string[] = [] // 描画対象のイメージid
    storage: AbstractStorage = null
    board_manager: AbstractBoardManager

    // supression
    $store: any
    $refs: any
    $route: any

    get imgs_index(): Map<string, ImgWithPosition> {
        const m = new Map();
        for(let img of this.imgs) {
            m.set(img.id, img);
        }
        return m
    }

    event_scroll(evt, el) {
        this.refresh_active_imgs();
    }

    event_wheel(e) {
        this.zoom(e);
        this.replace_reduce_blob();
        this.refresh_active_imgs();
    }

    event_mousemove(e) {
        /**マウスイベントを配給する */
        this.mousemove_for_imgmove(e);
        this.mousemove_for_resize(e);
    }

    event_mousedown(e) {
    }

    event_mouseup(e) {
        this.release_img();
        this.end_resize();
    }

    event_drop_item(e) {
        const dt = e.dataTransfer;
        const files = dt.files;
        const [x, y] = this.get_offset(e);
        this.upload_image(x, y, files);
        //this.refresh_active_imgs();
    }

    event_paste(e: ClipboardEvent) {
        const items = e.clipboardData.items;
        for(let i = 0; i < items.length; i++ ) {
            if(items[i].type.indexOf("image") != -1) {
                const file = items[i].getAsFile();
                this.upload_image_without_position([file]);
            }
        }
    }

    get styles() {
        return {
            '--height': this.board.height + "px",
            '--width': this.board.width + "px",
            '--scale': this.zoom_rate,
            // modal表示時に画面を暗くする
            '--board-screen': (this.$store.state.board_modal ? 0.7 : 0.4)
        }
    };

    get background_theme() {

        let theme_class = null;
        switch(this.board.theme) {
            case Theme.MONO_CHALKBLUE:
                theme_class = 'board_background-mono-chalkblue';
                break;
            default:
            case Theme.CORKBOARD:
                theme_class = 'board_background-corkboard'
                break;
        }
        return [theme_class];
    }

    /**
     * 描画対象イメージのリストを更新する
     */
    refresh_active_imgs() {
        const ids = this.imgs
            .filter(x => this.is_limited(x)).map(x => x.id);
        this.view_img_ids.length = 0;
        this.view_img_ids.push(...ids);

    }

    is_limited(img_pos: ImgWithPosition): boolean {
        /**
         * 該当画像が画面内かどうか判定する
         */
        const margin = 1000; // 広めに取る範囲
        const frame_width = this.$refs.frame.clientWidth / this.zoom_rate;
        const frame_height = this.$refs.frame.clientHeight / this.zoom_rate;
        const frame_top = this.$refs.frame.scrollTop / this.zoom_rate;
        const frame_left = this.$refs.frame.scrollLeft / this.zoom_rate;

        const c1 = img_pos.pos.x + img_pos.pos.fixed_width > frame_left - margin;
        const c2 = img_pos.pos.x < frame_left + frame_width + margin;
        const c3 = img_pos.pos.y + img_pos.pos.fixed_height > frame_top - margin;
        const c4 = img_pos.pos.y < frame_top + frame_height + margin;

        return c1 && c2 && c3 && c4;
    }

    is_active_img(img_id: string): boolean {
        return this.view_img_ids.indexOf(img_id) != -1;
    }

    /**　画面をリセット */
    view_reset() {
        this.zoom_step = 0; // TODO: リアクティブにzoom_rateを計算させたい
        this.zoom_rate = 0.5;
        let center_x = (this.board.width/2-this.$refs.frame.offsetWidth/2) * this.zoom_rate;
        let center_y = (this.board.height/2-this.$refs.frame.offsetHeight/2) * this.zoom_rate;
        this.$refs.frame.scrollTo(center_x, center_y);
    }

    async mounted() {
        this.$store.commit('zoom_change', this.zoom_rate);
        //this.zoom_rate = this.$store.state.session.zoom_rate;

        // 画面リセット
        this.$nextTick(function() {
            this.view_reset();
        });
        this.init();
    }

    /**ルーターで変化が起こった*/
    @Watch('$route')
    beforeRouteUpdate() {
        this.init();
    }

    /**ボードの初期化処理 */
    async init() {
        this.$store.commit('start_loading');

        this.board_manager = board_manager_factory();
        const path = this.$route.params.board_path;

        // ボード情報の取得
        this.board = await this.board_manager.get_board(path);
        if(this.board == undefined) {
            const boards = await this.board_manager.get_boards();
            const num = boards.length;
            const board = new Board(path, `board${num}`, 50000, 75000, Theme.CORKBOARD);
            await this.board_manager.insert_board(board);
            this.board = await this.board_manager.get_board(path);
        }

        // ボードのストレージ取得
        this.storage = new CachedLocalStorage(this.board);

        this.imgs = [];　// imgsの初期化
        const ids = await this.storage.get_ids();
        let promises = ids.map(id => this.storage.get(id));
        for(let p of promises) {
            // ロードを完了したものから描画
            const img_with_pos = await p;
            this.imgs.push(img_with_pos);
        }
        this.refresh_active_imgs();
        // 素早く完了すれば次の描画までに画像を圧縮できる
        this.replace_reduce_blob();
        this.view_reset();
        this.$store.commit('end_loading');
    }

    change_theme(theme) {
        this.board.theme = theme;
        this.board_manager.update_board(this.board)
    }
}
