import Vue from 'vue';
import { AbstractStorage, ImgWithPosition } from './storage/header';
import {Watch, Mixins} from 'vue-property-decorator';
import img_position  from './img_position';
import { Component } from 'vue-property-decorator';

@Component
export default class MoveComponent extends Mixins(img_position) {

    move_img: ImgWithPosition = null;
    move_offset_x = null; // マウスでクリックした画像上の座標
    move_offset_y = null;

    // supression
    zoom_rate: number;
    storage: AbstractStorage;

    select_img(e, img) {
        if(this.$store.state.lock){return}
        console.log("select img.", img.id);
        this.move_img = img;
        this.move_offset_x = e.offsetX - this.move_img.pos.fixed_width / 2;
        this.move_offset_y = e.offsetY - this.move_img.pos.fixed_height / 2;
    }

    release_img() {
        console.log("release img.");
        if(this.move_img){
            let img = this.move_img;
            this.storage.update(img.id, img.pos);
        }
        this.move_img = null;
    }

    mousemove_for_imgmove(e) {
        if(this.move_img) {
            let [x, y] = this.get_offset(e).map(x => x);
            this.move_img.pos.x = x - this.move_offset_x;
            this.move_img.pos.y = y - this.move_offset_y;
        }
    }

}
